/*
=====================================================================
Design system
=====================================================================*/
:root {
    /* Color palette */
    --color-primary-charcoal: #33363A;
    --color-primary-white: #FFFFFF;

    --color-secondary-black: #000000;
    --color-secondary-charcoal-soft: #4F5458;
    --color-secondary-blue: #0F9FB7;

    --color-accent-red: #E74C3C;

    --color-neutral-deep: #111111;
    --color-neutral-muted: #B0B0B0;
    --color-neutral-bg: #F5F5F5;
    --color-neutral-line: #E0E0E0;

    --color-success: #27AE60;
    --color-error: #E74C3C;
    --color-warning: #F39C12;
    --color-info: #3498DB;

    /* Typography */
    --font-heading: 'Space Grotesk', Helvetica, sans-serif;
    --font-body: 'Source Sans 3', Arial, sans-serif;
    --font-code: 'JetBrains Mono', monospace;

    --font-size-h1: 40px;
    --font-size-h2: 28px;
    --font-size-h3: 22px;
    --font-size-body: 16px;
    --font-size-small: 13px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-xxs: 4px;
    --space-xs: 8px;
    --space-sm: 16px;
    --space-md: 24px;
    --space-lg: 32px;
    --space-xl: 48px;
    --space-xxl: 64px;

    /* Layout */
    --site-max-width: 1280px;
    --header-height: 64px;
    --promo-height: 36px;
    --nav-link-spacing: 24px;
}

/*
=====================================================================
Global resets & base
=====================================================================*/
* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-primary-charcoal);
    background-color: var(--color-neutral-bg);
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

img {
    max-width: 100%;
    display: block;
}

ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

button,
input,
textarea,
select {
    font: inherit;
}

/*
=====================================================================
Promo bar
=====================================================================*/
.promo-bar {
    background-color: var(--color-secondary-black);
    color: var(--color-primary-white);
    font-family: var(--font-heading);
    font-size: var(--font-size-small);
    text-transform: uppercase;
    letter-spacing: 0.12em;
}

.promo-bar__inner {
    max-width: var(--site-max-width);
    margin: 0 auto;
    padding: 0 var(--space-sm);
    height: var(--promo-height);
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
}

.promo-bar__message {
    margin: 0;
    text-align: center;
}

.promo-bar__close-symbol {
    position: absolute;
    right: var(--space-sm);
    top: 50%;
    transform: translateY(-50%);
    font-size: 16px;
    opacity: 0.8;
}

/*
=====================================================================
Header & primary navigation
=====================================================================*/
.site-header {
    background-color: var(--color-primary-charcoal);
    color: var(--color-primary-white);
    border-bottom: 1px solid rgba(0, 0, 0, 0.55);
}

.site-header__inner {
    max-width: var(--site-max-width);
    margin: 0 auto;
    padding: 0 var(--space-sm);
    height: var(--header-height);
    display: grid;
    grid-template-columns: minmax(0, 1.4fr) auto minmax(0, 1.4fr);
    align-items: stretch;
    column-gap: var(--space-sm);
}

/* Primary nav (left) */
.main-nav {
    display: flex;
    align-items: center;
}

.main-nav__list {
    display: flex;
    flex-wrap: nowrap;
    gap: var(--nav-link-spacing);
    overflow-x: auto;
    padding-bottom: 2px; /* avoid scrollbar overlap */
}

.main-nav__item {
    white-space: nowrap;
}

.main-nav__link {
    font-family: var(--font-heading);
    font-size: var(--font-size-small);
    font-weight: var(--font-weight-medium);
    text-transform: uppercase;
    letter-spacing: 0.14em;
    color: var(--color-primary-white);
    position: relative;
    padding: 0 0 2px 0;
}

.main-nav__link::after {
    content: '';
    position: absolute;
    left: 0;
    bottom: 0;
    width: 0;
    height: 2px;
    background-color: var(--color-accent-red);
    transition: width 0.18s ease-out;
}

.main-nav__link:hover::after,
.main-nav__link:focus-visible::after {
    width: 100%;
}

.main-nav__link:hover,
.main-nav__link:focus-visible {
    text-decoration: none;
}

/* Inline-style nav item (for when cart also appears in utility area) */
.main-nav__link--inline {
    opacity: 0.85;
}

/* Branding (center) */
.site-branding {
    display: flex;
    align-items: center;
    justify-content: center;
}

.site-logo {
    display: flex;
    align-items: center;
    gap: var(--space-xs);
    color: var(--color-primary-white);
}

.site-logo__mark {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 6px 8px;
    background-color: var(--color-secondary-black);
    border-radius: 2px;
}

.site-logo__pill {
    display: block;
    width: 6px;
    height: 20px;
    margin: 0 2px;
    background-color: var(--color-primary-white);
}

.site-logo__pill--center {
    height: 24px;
}

.site-logo__pill--left,
.site-logo__pill--right {
    background-color: var(--color-secondary-blue);
}

.site-logo__text-group {
    display: flex;
    flex-direction: column;
    line-height: 1.1;
}

.site-logo__name {
    font-family: var(--font-heading);
    font-size: 15px;
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.18em;
    text-transform: uppercase;
}

.site-logo__tagline {
    font-family: var(--font-body);
    font-size: 11px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    opacity: 0.85;
}

/* Utilities: search + cart (right) */
.site-tools {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--space-md);
}

/* Search */
.site-search {
    display: flex;
    align-items: center;
    gap: var(--space-xs);
}

.site-search__label {
    font-family: var(--font-heading);
    font-size: var(--font-size-small);
    font-weight: var(--font-weight-medium);
    text-transform: uppercase;
    letter-spacing: 0.16em;
}

.site-search__form {
    display: flex;
    align-items: stretch;
    background-color: var(--color-secondary-charcoal-soft);
    border: 1px solid #26292b;
    min-width: 210px;
}

.site-search__input {
    flex: 1 1 auto;
    border: none;
    background-color: transparent;
    color: var(--color-primary-white);
    padding: 8px 10px;
    font-size: 14px;
}

.site-search__input::placeholder {
    color: var(--color-neutral-muted);
}

.site-search__input:focus-visible {
    outline: none;
}

.site-search__submit {
    flex: 0 0 40px;
    border: none;
    background-color: transparent;
    color: var(--color-primary-white);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    border-left: 1px solid #26292b;
}

.site-search__submit:hover,
.site-search__submit:focus-visible {
    background-color: rgba(0, 0, 0, 0.32);
}

.site-search__submit-icon {
    font-size: 16px;
}

/* Cart link (rightmost button) */
.cart-link {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    background-color: var(--color-accent-red);
    color: var(--color-primary-white);
    padding: 0 16px;
    height: 40px;
    font-family: var(--font-heading);
    font-size: 13px;
    font-weight: var(--font-weight-semibold);
    text-transform: uppercase;
    letter-spacing: 0.14em;
}

.cart-link:hover,
.cart-link:focus-visible {
    text-decoration: none;
    background-color: #c0392b;
}

.cart-link__count {
    min-width: 18px;
    height: 18px;
    border-radius: 2px;
    background-color: rgba(0, 0, 0, 0.25);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-size: 11px;
}

/*
=====================================================================
Main content area
=====================================================================*/
.site-main {
    max-width: var(--site-max-width);
    margin: 0 auto;
    padding: var(--space-xl) var(--space-sm) var(--space-xxl);
    min-height: 50vh;
}

/* Generic heading styling to match aesthetic */
.site-main h1,
.site-main h2,
.site-main h3 {
    font-family: var(--font-heading);
    letter-spacing: 0.08em;
    text-transform: uppercase;
}

.site-main h1 {
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
}

.site-main h2 {
    font-size: var(--font-size-h2);
}

.site-main h3 {
    font-size: var(--font-size-h3);
}

/*
=====================================================================
Footer
=====================================================================*/
.site-footer {
    background-color: var(--color-neutral-deep);
    color: var(--color-neutral-muted);
    border-top: 1px solid #000000;
}

.site-footer__inner {
    max-width: var(--site-max-width);
    margin: 0 auto;
    padding: var(--space-lg) var(--space-sm) var(--space-xl);
}

.footer-nav__list {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-sm) var(--space-lg);
    margin-bottom: var(--space-md);
}

.footer-nav__link {
    font-family: var(--font-heading);
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.16em;
    color: var(--color-neutral-muted);
}

.footer-nav__link:hover,
.footer-nav__link:focus-visible {
    color: var(--color-primary-white);
    text-decoration: none;
}

.footer-nav__item--accent .footer-nav__link {
    color: var(--color-primary-white);
}

.footer-nav__item--accent .footer-nav__link::after {
    content: '';
    display: block;
    width: 24px;
    height: 2px;
    margin-top: 4px;
    background-color: var(--color-accent-red);
}

.site-footer__meta {
    margin: 0;
    font-size: 13px;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 6px;
}

.site-footer__brand {
    font-family: var(--font-heading);
    letter-spacing: 0.14em;
    text-transform: uppercase;
}

.site-footer__divider {
    opacity: 0.6;
}

.site-footer__copyright {
    opacity: 0.85;
}

/*
=====================================================================
Responsive adjustments
=====================================================================*/
@media (max-width: 960px) {
    .site-header__inner {
        grid-template-columns: minmax(0, 1fr);
        grid-auto-rows: auto;
        row-gap: var(--space-xs);
        height: auto;
        padding-top: var(--space-xs);
        padding-bottom: var(--space-xs);
    }

    .site-branding {
        order: -1;
        padding-bottom: var(--space-xs);
    }

    .site-tools {
        justify-content: space-between;
    }

    .site-search__form {
        min-width: 0;
        width: 100%;
    }
}

@media (max-width: 640px) {
    .promo-bar__inner {
        padding-right: var(--space-md);
    }

    .site-main {
        padding: var(--space-lg) var(--space-xs) var(--space-xl);
    }

    .site-tools {
        flex-direction: column;
        align-items: stretch;
        gap: var(--space-xs);
    }

    .site-search {
        justify-content: space-between;
    }

    .cart-link {
        justify-content: center;
        width: 100%;
    }

    .footer-nav__list {
        flex-direction: column;
        gap: var(--space-xs);
    }
}
